// Coleta todos os itens vindos dos feeds RSS combinados pelo Merge.
const allItems = $input.all();
const now = new Date();
const cutoff48h = new Date(now.getTime() - 48 * 60 * 60 * 1000);
const cutoff72h = new Date(now.getTime() - 72 * 60 * 60 * 1000);

// Regras para identificar a fonte e a categoria a partir do link/conteudo.
// (fontes 100% ficticias - apenas demonstracao)
const sourceRules = [
  { match: ['blog.exemplo.dev'],      source: 'Blog Exemplo',        category: 'Tecnologia e negocios' },
  { match: ['noticias.exemplo.dev'],  source: 'Portal Noticias',     category: 'Mercado e investimentos' },
  { match: ['automacao.exemplo.dev'], source: 'Automacao Exemplo',   category: 'Automacao empresarial' },
  { match: ['financas.exemplo.dev'],  source: 'Financas Exemplo',    category: 'Financas e gestao' },
  { match: ['pesquisa.exemplo.dev'],  source: 'Pesquisa Exemplo',    category: 'Pesquisa e inovacao' },
  { match: ['startups.exemplo.dev'],  source: 'Startups Exemplo',    category: 'Mercado e investimentos' },
];

function textOf(value) {
  return String(value || '').toLowerCase();
}

// Classifica cada item em uma fonte/categoria conhecida ou generica.
function classify(item) {
  const link = item.link || item.guid || '';
  const haystack = [link, item.title, item.contentSnippet, item.summary, item.description]
    .map(textOf).join(' ');
  for (const rule of sourceRules) {
    if (rule.match.some(function (pattern) { return haystack.includes(pattern); })) {
      return { source: rule.source, category: rule.category, link };
    }
  }
  try {
    return { source: new URL(link).hostname.replace(/^www\./, ''), category: 'Fonte monitorada', link };
  } catch (e) {
    return { source: 'Fonte monitorada', category: 'Fonte monitorada', link };
  }
}

function parseDate(j) {
  for (const f of [j.pubDate, j.isoDate, j.date, j.published]) {
    if (f) {
      const d = new Date(f);
      if (!isNaN(d.getTime())) return d;
    }
  }
  return new Date(0);
}

// Pontua cada noticia por utilidade para um publico de gestores.
function relevanceScore(item) {
  const text = [item.title, item.contentSnippet, item.summary, item.description, item._category]
    .map(textOf).join(' ');
  const strong = ['enterprise', 'corporativo', 'negocio', 'financas', 'gestao', 'automacao',
    'workflow', 'agente', 'investimento', 'rodada', 'aquisicao', 'produtividade', 'roi'];
  const medium = ['ia', 'inteligencia artificial', 'dados', 'nuvem', 'integracao', 'api', 'plataforma'];
  const weak = ['game', 'gadget', 'rumor', 'celebridade', 'meme', 'fofoca'];
  let score = 0;
  strong.forEach(function (t) { if (text.includes(t)) score += 4; });
  medium.forEach(function (t) { if (text.includes(t)) score += 2; });
  weak.forEach(function (t) { if (text.includes(t)) score -= 5; });
  return score;
}

// Enriquecimento: data, fonte, categoria, link e score por item.
const candidates = allItems.map(function (item) {
  const json = item.json || {};
  const classified = classify(json);
  const enriched = Object.assign({}, json, {
    _date: parseDate(json),
    _source: classified.source,
    _category: classified.category,
    _link: classified.link,
  });
  enriched._score = relevanceScore(enriched);
  return enriched;
});

// Janela de recencia com fallback progressivo se houver poucas noticias.
let filtered = candidates.filter(function (i) { return i._date >= cutoff48h; });
if (filtered.length < 8) filtered = candidates.filter(function (i) { return i._date >= cutoff72h; });
if (filtered.length < 5) filtered = candidates.slice().sort(function (a, b) { return b._date - a._date; }).slice(0, 30);

// Remove duplicatas por titulo/link.
const seen = new Set();
const unique = filtered.filter(function (i) {
  const titleKey = String(i.title || '').toLowerCase().trim().substring(0, 90);
  const linkKey = String(i._link || i.link || '').replace(/[?#].*$/, '').toLowerCase();
  const key = titleKey || linkKey;
  if (!key || seen.has(key)) return false;
  seen.add(key);
  return true;
}).sort(function (a, b) { return (b._score - a._score) || (b._date - a._date); });

// Seleciona as melhores noticias e monta o bloco de contexto para a IA.
const selected = unique.slice(0, 20);

const noticias = selected.map(function (item, idx) {
  const title = String(item.title || 'Sem titulo').trim();
  const link = item._link || item.link || item.guid || '';
  const source = item._source;
  const category = item._category;
  const date = item._date.getTime() > 0 ? item._date.toLocaleDateString('pt-BR') : 'Data nao informada';
  const summary = String(item.contentSnippet || item.summary || item.description || '')
    .replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 400);
  return '[' + (idx + 1) + ']\n' +
    'CATEGORIA: ' + category + '\n' +
    'TITULO: ' + title + '\n' +
    'FONTE: ' + source + '\n' +
    'DATA: ' + date + '\n' +
    'URL: ' + link + '\n' +
    'RESUMO: ' + summary + '\n---';
}).join('\n\n');

// Metadados da edicao.
const dataFormatada = now.toLocaleDateString('pt-BR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
}).replace(/^./, function (c) { return c.toUpperCase(); });

const inicio = new Date('2026-01-01');
const edicao = Math.max(1, Math.floor((now - inicio) / 86400000) + 1);
const assunto = '[Boletim IA] ' +
  now.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' }) +
  ' | Ed. ' + edicao;

// Prompt de sistema: define papel e formato de saida (HTML puro).
const promptSistema = 'Voce e um editor executivo especialista em tecnologia, inteligencia ' +
  'artificial, automacao e gestao. Escreve em portugues brasileiro claro e objetivo. ' +
  'REGRA ABSOLUTA: retorne APENAS HTML puro completo iniciando com <!DOCTYPE html>. ' +
  'Proibido markdown, comentarios ou texto fora do HTML.';

// Prompt de usuario: instrucoes de secoes, design e as noticias do dia.
const promptUsuario =
  'Hoje e ' + dataFormatada + '. Edicao numero ' + edicao + '.\n\n' +
  'Crie uma NEWSLETTER EXECUTIVA em portugues brasileiro, em HTML completo para e-mail.\n\n' +
  'SECOES ESPERADAS:\n' +
  '1. DESTAQUE DO DIA - a noticia mais relevante para gestores.\n' +
  '2. AUTOMACAO EMPRESARIAL - workflows, agentes e integracoes.\n' +
  '3. FINANCAS E GESTAO - planejamento, ERP e processos.\n' +
  '4. MERCADO E INVESTIMENTOS - rodadas, aquisicoes e movimentos relevantes.\n' +
  '5. ANALISE DO DIA - sintese editorial de 3 a 5 linhas.\n\n' +
  'REGRAS DE DESIGN (compativel com clientes de e-mail):\n' +
  '- Retorne HTML completo iniciando com <!DOCTYPE html> e <html lang="pt-BR">.\n' +
  '- Use <body style="margin:0;padding:0;background-color:#f2f2f2;">.\n' +
  '- Container central com tabela: max-width 600px, fundo branco, fonte Arial.\n' +
  '- Use apenas estilos inline. Nao use flexbox, grid, box-shadow ou linear-gradient.\n' +
  '- Titulos de noticias devem ser links clicaveis com a URL real.\n' +
  '- Cor de acento #2563EB e textos em tons de cinza.\n\n' +
  'REGRAS DE CONTEUDO:\n' +
  '- Use APENAS as noticias fornecidas abaixo para fatos e numeros.\n' +
  '- No maximo 2 noticias por secao (exceto destaque e analise).\n' +
  '- Omita secoes sem noticias relevantes.\n' +
  '- Tom executivo, direto e analitico.\n\n' +
  'NOTICIAS DO DIA (use APENAS estas ' + selected.length + ' noticias):\n\n' + noticias;

return [{
  json: {
    prompt_sistema: promptSistema,
    prompt_usuario: promptUsuario,
    assunto_email: assunto,
    data_hoje: dataFormatada,
    numero_edicao: edicao,
    total_noticias: selected.length,
  },
}];

// Extrai o HTML retornado pela API de IA, tratando formatos comuns de resposta.
const response = $input.first().json;
let html = '';

if (response.choices && response.choices[0] && response.choices[0].message) {
  html = response.choices[0].message.content || '';
} else if (response.message && response.message.content) {
  html = response.message.content;
} else if (response.error) {
  throw new Error('Erro da API de IA: ' + JSON.stringify(response.error));
}

// Remove eventuais cercas de markdown que a IA possa ter adicionado.
html = String(html || '')
  .replace(/^```html\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```\s*$/, '')
  .trim();

// Se a resposta foi cortada por limite de tokens, falha de forma explicita.
const finishReason = response.choices && response.choices[0] ? response.choices[0].finish_reason : '';
if (finishReason === 'length') {
  throw new Error('Resposta cortada por limite de tokens. Aumente max_tokens e execute novamente.');
}

// Validacoes basicas de estrutura e compatibilidade com clientes de e-mail.
const erros = [];
if (!html || html.length < 500) erros.push('HTML vazio ou curto demais');
if (!/^<!DOCTYPE html>/i.test(html)) erros.push('HTML precisa iniciar com <!DOCTYPE html>');
if (!/<html[\s>]/i.test(html)) erros.push('Tag <html> ausente');
if (!/<body[\s>]/i.test(html)) erros.push('Tag <body> ausente');
if (/```/.test(html)) erros.push('Markdown/code fence encontrado no HTML');
if (/linear-gradient\s*\(/i.test(html)) erros.push('linear-gradient nao recomendado para e-mail');
if (/display\s*:\s*(flex|grid)/i.test(html)) erros.push('flexbox/grid nao recomendado para e-mail');
if (!/href\s*=\s*["']/i.test(html)) erros.push('Nenhum link clicavel encontrado');

// Fecha tags principais caso a resposta tenha vindo levemente incompleta.
if (!/<\/html>\s*$/i.test(html) && /<body[\s>]/i.test(html) && html.length > 1500) {
  if (!/<\/body>/i.test(html)) html += '\n</body>';
  html += '\n</html>';
}

if (erros.length) {
  throw new Error('HTML invalido para envio: ' + erros.join('; '));
}

const codeData = $('Code - Filtrar e Formatar').first().json;

return [{
  json: {
    html_newsletter: html,
    assunto_email: codeData.assunto_email || 'Boletim Executivo de IA',
    html_validado: true,
  },
}];
